INSERT INTO products (id, category_id, kitchen_station_id, name, description, price, is_available, is_enabled, priority, image_url, stock_quantity, min_stock_level, unit_measure, created_at, product_code, short_name, cost_price, classification, portions, portion_size, serving_temp, prep_time, prepared_by, prep_procedure, observations, inventory_item_id, branch_id, menu_category_id, product_category_id, es_platillo, presentation_unit, conversion_factor, supplier_id, stock_actual, updated_at, recipe_no) VALUES ('8cf7aaaf-5f0f-45e0-b3b6-5b6c5337bc45', NULL, NULL, 'BACH FRIJOLES PREPARADOS CON CARNE 9 PORCIONES 14 ', NULL, 0, true, true, 100, NULL, 0, 5, 'Onza', '2026-05-05T21:26:10.157402-06:00', '', NULL, 99.51, 'BACH', 1, '14', 'CALIENTE', '45', 'AMALIA DE LA CRUZ', 'EL FRIJOL SE COCEN PRIMERO, LUEGO LA CARNE MOLIDA SE SOFRIE AL ESTAR SOFRITA SE LE AGREGA LA CEBOLLA, CHILE PIMIENTO, AJO Y SE MEZCLAM EN EL SARTEN. AL SIGUIENTE DIA SE PORCIONA EN 14 ONZAS POR PORCION.					
INSERT INTO products (id, category_id, kitchen_station_id, name, description, price, is_available, is_enabled, priority, image_url, stock_quantity, min_stock_level, unit_measure, created_at, product_code, short_name, cost_price, classification, portions, portion_size, serving_temp, prep_time, prepared_by, prep_procedure, observations, inventory_item_id, branch_id, menu_category_id, product_category_id, es_platillo, presentation_unit, conversion_factor, supplier_id, stock_actual, updated_at, recipe_no) VALUES ('158ff6fa-c2f8-40e4-a9e9-607ff7cc5b96', NULL, NULL, 'CHILE CHINO ONZA', NULL, 0, true, true, 100, NULL, 0, 5, 'Onza', '2026-04-23T22:15:15.737094-06:00', '', NULL, 20.16, 'PICANTE', 1, '41', 'AMBIENTE', '15', 'AMALIA', 'En la licuadora, agregamos el ajo y el aceite. Licuamos hasta que el ajo esté bien procesado, apagamos la licuadora y añadimos el chile cobán. Licuamos nuevamente hasta que el chile esté semimolido, cuidando que no se licúe por completo. Vertemos la mezcla en una olla pequeña y la ponemos a cocer; cuando empiece a hervir, movemos con una paleta para que no se pegue. Finalmente, apagamos el fuego y retiramos la olla de la estufa para que no se siga cocinando.', 'VERTEMOS LA MEZCLA EN UNA OLLA PEQUEÑA Y LA PONEMOS A COCER; CUANDO EMPIECE A HERVIR, MOVEMOS CON UNA PALETA PARA QUE NO SE PEGUE. FINALMENTE, APAGAMOS EL FUEGO Y RETIRAMOS LA OLLA DE LA ESTUFA PARA QUE NO SE SIGA COCINANDO.', NULL, NULL, NULL, '4fd547d1-2667-4d7f-b6cf-947be65cdaf8', false, 'Bolsa', 41, '5e3fc5af-6d6e-43b8-88c3-8963598693f4', 0, '2026-04-23T16:15:15.737094-06:00', '07');
